UPDATE TBL_INBOUND_PRODUCT SET
    DELETED_YN = 'Y',
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{updtUser}
WHERE TBL_INBOUND_PRODUCT_ID = #{tblInboundProductId}
AND INBOUND_STATUS = 'PENDING'
